export type Capture<T> = Pick<T, never>;

export type FieldsFor<T> = {
    [P in keyof T]: InferredFieldType<T[P]>;
};

export type LenientField<
    T = unknown,
    FIELD extends keyof T = keyof T,
    VALUE_TYPE extends T[FIELD] = T[FIELD],
> = Capture<VALUE_TYPE> & Pick<InferredFieldType<VALUE_TYPE>, "value">;

export type LenientFieldsFor<T> = {
    [P in keyof T]: LenientField<T, P>;
};

export type Field<T = unknown, FIELD_TYPE extends FieldType = FieldType> =
    | SingleValueField<UnWrapElementTypeIfArray<T>, FIELD_TYPE>
    | MultiValueField<UnWrapElementTypeIfArray<T>, FIELD_TYPE>
    | StringTreeSuggestField;

export type UnWrapElementTypeIfArray<T> = T extends (infer U)[] ? U : T;

export type InferredFieldType<T = unknown, FIELD_TYPE extends FieldType = FieldType> = Capture<T> &
    Capture<FIELD_TYPE> &
    (T extends Array<infer ArrayValueType>
        ? ArrayValueType extends StringTreeSuggestPath
            ? StringTreeSuggestField
            : MultiValueField<ArrayValueType, FIELD_TYPE>
        : SingleValueField<T, FIELD_TYPE>);

export type FieldType =
    | "BOOLEAN"
    | "BYTES"
    | "DATETIME"
    | "DECIMAL"
    | "DECIMALSUGGEST"
    | "DOUBLE"
    | "DOUBLESUGGEST"
    | "INT"
    | "INTSUGGEST"
    | "LONG"
    | "LONGSUGGEST"
    | "STRING"
    | "STRINGSUGGEST"
    | "STRINGLISTSUGGEST"
    | "STRINGTREESUGGEST"
    | "SELECTIONVALUELIST"
    | "GGUID"
    | "TEXT"
    | "CURRENCY"
    | "CURRENCYSUGGEST"
    | "USERID"
    | "TYPESTATUSSUGGEST";

export const FIELD_TYPES_WITH_PARSE_SUPPORT = [
    "BOOLEAN",
    "DATETIME",
    "DECIMAL",
    "DECIMALSUGGEST",
    "DOUBLE",
    "DOUBLESUGGEST",
    "INT",
    "INTSUGGEST",
    "LONG",
    "LONGSUGGEST",
    "STRING",
    "STRINGSUGGEST",
    "GGUID",
    "TEXT",
    "CURRENCY",
    "CURRENCYSUGGEST",
    "TYPESTATUSSUGGEST",
] as const;

export type FieldTypesWithParseSupport = (typeof FIELD_TYPES_WITH_PARSE_SUPPORT)[number];

export const FIELD_TYPES_WITH_FORMAT_SUPPORT = [
    "BOOLEAN",
    "DATETIME",
    "DECIMAL",
    "DECIMALSUGGEST",
    "DOUBLE",
    "DOUBLESUGGEST",
    "INT",
    "INTSUGGEST",
    "LONG",
    "LONGSUGGEST",
    "STRING",
    "STRINGSUGGEST",
    "STRINGLISTSUGGEST",
    "STRINGTREESUGGEST",
    "SELECTIONVALUELIST",
    "GGUID",
    "TEXT",
    "CURRENCY",
    "CURRENCYSUGGEST",
    "USERID",
    "TYPESTATUSSUGGEST",
] as const;

export type FieldTypesWithFormatSupport = (typeof FIELD_TYPES_WITH_FORMAT_SUPPORT)[number];

export type IsFormatSupportedFieldType<FIELD_TYPE = FieldType> = FIELD_TYPE extends FieldTypesWithFormatSupport
    ? true
    : false;

export type IsParseSupportedFieldType<FIELD_TYPE = FieldType> = FIELD_TYPE extends FieldTypesWithParseSupport
    ? true
    : false;

export type FieldValueParser<VALUE_TYPE> = {
    /**
     * Attempts to parse the given presentation value to the model value, might be unsupported or unreliable for certain data types.
     *
     * In case when parsing is unsupported or an error occurs, the returned Promise will be rejected.
     * @param presentation The presentation value
     */
    parse(presentation: string): Promise<VALUE_TYPE>;
};

export type FieldValueFormatter<VALUE_TYPE> = {
    /**
     * Returns the formatted variant of the given model value.
     *
     * In case when formatting is unsupported or an error occurs, the returned Promise will be rejected.
     * @param value The value from the model
     */
    format(value: VALUE_TYPE): Promise<string>;
};

export type FieldValueConverter<VALUE_TYPE, FIELD_TYPE> = //
    Capture<VALUE_TYPE> &
        Capture<FIELD_TYPE> &
        (IsParseSupportedFieldType<FIELD_TYPE> extends true ? FieldValueParser<VALUE_TYPE> : unknown) &
        (IsFormatSupportedFieldType<FIELD_TYPE> extends true ? FieldValueFormatter<VALUE_TYPE> : unknown);

export type FieldMetadata<VALUE_TYPE = unknown, FIELD_TYPE = FieldType> = {
    /**
     * The type of the field
     */
    readonly fieldType?: FIELD_TYPE;
    /**
     * Contains the name of the object type for which this field belongs to
     */
    readonly objectTypeName: string;
    /**
     * Contains the name for this field
     */
    readonly fieldName: string;
    /**
     * Contains the label for this field
     */
    readonly label: string;
    /**
     * True if the current user has read access on this field.
     */
    readonly readable: boolean;
    /**
     * True if the user has the privilege to update values for this field.
     */
    readonly updateable: boolean;
    /**
     * True for mandatory fields.
     */
    readonly mandatory: boolean;
    /**
     * True for recommended fields.
     */
    readonly recommended: boolean;
    /**
     * True for hidden fields.
     */
    readonly hidden: boolean;
    /**
     * True for custom fields.
     */
    readonly custom: boolean;
    /**
     * The field specific converter
     */
    readonly converter?: FieldValueConverter<VALUE_TYPE, FIELD_TYPE>;
};

export type FieldInfo<VALUE_TYPE = unknown, FIELD_TYPE extends FieldType = FieldType> = FieldMetadata<
    VALUE_TYPE,
    FIELD_TYPE
> & {
    /**
     * Contains the description of a potential validation failure
     */
    readonly validationMessage: string;
    /**
     * Contains the validation state set by the last value change
     */
    readonly validationState: "valid" | "warning" | "error";

    /**
     * Current value of the field
     */
    value: VALUE_TYPE;

    /**
     * The formatted value of the field.
     * If the field value converters are not supported, or the field value was changed, it will be undefined.
     */
    readonly formattedValue?: string;
    /**
     * Unit to be displayed, usually concatenated to the formatted value
     */
    readonly unit?: string;
};

export type FieldWithPossibleValue<VALUE_TYPE, SUGGESTION_TYPE, FIELD_TYPE extends FieldType = FieldType> = FieldInfo<
    VALUE_TYPE,
    FIELD_TYPE
> & {
    /**
     * The list of possible values for the current field, if it provides any.
     */
    possibleValues?: SUGGESTION_TYPE[];
};

export type FieldMetadataWithPossibleValue<
    VALUE_TYPE,
    SUGGESTION_TYPE,
    FIELD_TYPE extends FieldType = FieldType,
> = FieldMetadata<VALUE_TYPE, FIELD_TYPE> & {
    /**
     * The list of possible values for the current field, if it provides any.
     */
    possibleValues?: SUGGESTION_TYPE[];
};

declare const SINGLE_VALUE_TYPE_SYMBOL: unique symbol;
declare const MULTI_VALUE_TYPE_SYMBOL: unique symbol;
declare const STRING_TREE_SUGGEST_VALUE_TYPE_SYMBOL: unique symbol;

export type SingleValueField<T = unknown, FIELD_TYPE extends FieldType = FieldType> = FieldWithPossibleValue<
    UnWrapElementTypeIfArray<T>,
    UnWrapElementTypeIfArray<T>,
    FIELD_TYPE
> & {
    /**
     * Marker to differentiate the different field types, exists on the type level only
     * @private
     */
    [SINGLE_VALUE_TYPE_SYMBOL]?: unknown;
};
export type MultiValueField<T = unknown, FIELD_TYPE extends FieldType = FieldType> = FieldWithPossibleValue<
    UnWrapElementTypeIfArray<T>[],
    UnWrapElementTypeIfArray<T>,
    FIELD_TYPE
> & {
    /**
     * Marker to differentiate the different field types, exists on the type level only
     * @private
     */
    [MULTI_VALUE_TYPE_SYMBOL]: unknown;
};

export type StringTreeSuggestField = FieldInfo<StringTreeSuggestPath[], "STRINGTREESUGGEST"> & {
    /**
     * Root node of the tree of possible values
     */
    root: StringTreeSuggestNode;
} & {
    /**
     * Marker to differentiate the different field types, exists on the type level only
     * @private
     */
    [STRING_TREE_SUGGEST_VALUE_TYPE_SYMBOL]: unknown;
};

export type StringTreeSuggestFieldMetadata = FieldMetadata<StringTreeSuggestPath[], "STRINGTREESUGGEST"> & {
    /**
     * Root node of the tree of possible values
     */
    root: StringTreeSuggestNode;
};

export type SelectionType = "single" | "multi";

export type StringTreeSuggestNode = {
    name: string;
    path: StringTreeSuggestPath;
    selectable: boolean;
    selectionType: SelectionType;
    childSelectionType: SelectionType;
    children: StringTreeSuggestNode[];
};

export type StringTreeSuggestPath = string[];

export type SelectionValue = {
    label: string;
    id: string;
};
