import type { SmartDesign as Host } from "../host/smartdesign_host";
import { Communicator } from "./communicator";
import { AppSettings, AppSettingsScope, AppSettingsSetMode } from "./settings";
import { StringKeyOf } from "./type-utils";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export class AppSettingsImpl<T extends Record<string, unknown> = any> implements AppSettings<T> {
    constructor(
        private communicator: Communicator<Host.IAPI>,
        private scope: AppSettingsScope,
        private appId: string,
    ) {}
    getAll(): Promise<Partial<T>> {
        return this.communicator.invokeRelaxed("getAllAppSettings", this.appId, this.scope);
    }
    setAll(values: Partial<T>, mode: AppSettingsSetMode = "EXTEND"): Promise<void> {
        return this.communicator.invokeRelaxed("setAllAppSettings", this.appId, this.scope, mode, values);
    }
    get<PROPERTY extends StringKeyOf<T> = StringKeyOf<T>>(propertyName: PROPERTY): Promise<T[PROPERTY]> {
        return this.communicator.invokeRelaxed("getAppSettings", this.appId, this.scope, propertyName);
    }
    set<PROPERTY extends StringKeyOf<T> = StringKeyOf<T>>(propertyName: PROPERTY, value: T[PROPERTY]): Promise<void> {
        const settings: T = {} as T;
        settings[propertyName] = value;
        return this.communicator.invokeRelaxed("setAllAppSettings", this.appId, this.scope, "EXTEND", settings);
    }
    delete(propertyName: StringKeyOf<T>): Promise<void> {
        return this.communicator.invokeRelaxed("deleteAppSettings", this.appId, this.scope, propertyName);
    }
}
