export type FieldChangeListener<VALUE> = (field: Field<VALUE>) => void;

function ensureArray<T>(value: T[] | undefined): T[] {
    return value || [];
}

function enhanceMassDataResponseWithAPIMethods<T, FIELD extends StringKeyOf<T>>(
    massDataResponse: ConditionalMassDataResponseType<T, FIELD, true, true>,
    fieldEnhancer: <FIELD extends FieldMetadata>(field: FIELD) => FIELD,
): ConditionalMassDataResponseType<T, FIELD, true, true> {
    enhanceFieldsWithAPIMethods(massDataResponse.columns || [], fieldEnhancer);
    massDataResponse.rows = (massDataResponse.rows || []).map((transferredRow) => {
        const row = { ...transferredRow };
        const allProps = Object.keys(row);
        const cells = {} as CellsFor<MassDataRow<T, FIELD>>;
        row.cells = cells;

        allProps.forEach((prop) => {
            if (prop.indexOf("_formatted") > -1 || prop.indexOf("_unit") > -1) {
                return;
            }
            if (prop === "selectionId") {
                return;
            }
            if (prop === "summary") {
                return;
            }
            if (prop === "smartTags") {
                return;
            }

            let metadata: FieldMetadata<T[FIELD]> | null = null;
            const originalMetadata: FieldMetadata<T[FIELD], FieldTypesWithFormatSupport & FieldTypesWithParseSupport> =
                massDataResponse.columns[prop];

            const wrapConverter = (): FieldValueConverter<T[FIELD], FieldType> => {
                let formatter: FieldValueFormatter<T[FIELD]> | null = null;
                let parser: FieldValueParser<T[FIELD]> = null;

                if (isFieldWithFormatSupport(originalMetadata) && originalMetadata.converter.format) {
                    formatter = {
                        async format(value: T[FIELD]) {
                            if (value === originalValue) {
                                return formattedValue;
                            }
                            return originalMetadata.converter.format(value);
                        },
                    };
                }
                if (isFieldWithParseSupport(originalMetadata) && originalMetadata.converter.parse) {
                    parser = {
                        async parse(presentation: string) {
                            return originalMetadata.converter.parse(presentation);
                        },
                    };
                }
                return {
                    ...formatter,
                    ...parser,
                };
            };
            const originalValue = row[prop];
            const formattedValue = row[prop + "_formatted"];
            const unit = row[prop + "_unit"];
            cells[prop as keyof Field] = {
                get metadata() {
                    if (metadata == null) {
                        metadata = {
                            ...originalMetadata,
                            converter: originalMetadata.converter ? wrapConverter() : undefined,
                        };
                    }
                    return metadata;
                },
                get value() {
                    return row[prop];
                },
                get formattedValue() {
                    return formattedValue;
                },
                get unit() {
                    return unit;
                },
            } satisfies Cell<T[FIELD], FieldType>;
        });
        allProps.forEach((prop) => {
            if (prop.indexOf("_formatted") > -1 || prop.indexOf("_unit") > -1) {
                delete row[prop];
            }
        });
        return row;
    });
    return massDataResponse;
}

function enhanceFieldsWithAPIMethods<T>(
    container: T,
    fieldEnhancer: <FIELD extends FieldMetadata>(field: FIELD) => FIELD,
): T {
    Object.keys(container).forEach((prop) => {
        const value = container[prop];
        if (isFieldMetadata(value)) {
            (container[prop] as FieldMetadata) = fieldEnhancer(value);
        }
    });
    return container;
}

export class ContextItemChangeNotifier {
    private contextItemToListeners: Record<string, VoidFunction[]> = {};
    constructor(private communicator: Communicator<Host.IAPI>) {
        this.communicator.expose(this, "onContextItemInvalidate");
    }

    onContextItemInvalidate(contextItemName: string): void {
        this.contextItemToListeners[contextItemName] = ensureArray(this.contextItemToListeners[contextItemName]);
        this.contextItemToListeners[contextItemName].forEach((p) => p());
    }

    registerInvalidateInterest(contextItemName: string, listener: VoidFunction): IDisposable {
        this.contextItemToListeners[contextItemName] = ensureArray(this.contextItemToListeners[contextItemName]);
        if (this.contextItemToListeners[contextItemName].length == 0) {
            this.communicator.invokeRelaxed("registerContextItemInvalidateInterest", contextItemName);
        }
        this.contextItemToListeners[contextItemName].push(listener);
        return {
            dispose: () => {
                this.contextItemToListeners[contextItemName] = ensureArray(
                    this.contextItemToListeners[contextItemName],
                );
                this.contextItemToListeners[contextItemName] = this.contextItemToListeners[contextItemName].filter(
                    (p) => p != listener,
                );
                if (this.contextItemToListeners[contextItemName].length == 0) {
                    this.communicator.invokeRelaxed("unregisterContextItemInvalidateInterest", contextItemName);
                }
            },
        };
    }
}

export class FieldValueChangeNotifier {
    private aliasToListeners: Record<string, FieldChangeListener<unknown>[]> = {};
    constructor(private communicator: Communicator<Host.IAPI>) {
        this.communicator.expose(this, "onFieldChange");
    }

    onFieldChange(contextItemName: string, fieldName: string, field: Field<unknown>): void {
        const alias = this.getAlias(contextItemName, fieldName);
        this.aliasToListeners[alias] = ensureArray(this.aliasToListeners[alias]);
        this.aliasToListeners[alias].forEach((p) => p(field));
    }

    private getAlias(contextItemName: string, fieldName: string): string {
        return `${contextItemName}.${fieldName}`;
    }

    registerFieldInterest<T, FIELD extends StringKeyOf<T>>(
        contextItemName: string,
        fieldName: FIELD,
        listener: FieldChangeListener<T[FIELD]>,
    ): IDisposable {
        const alias = this.getAlias(contextItemName, fieldName);

        this.aliasToListeners[alias] = ensureArray(this.aliasToListeners[alias]);
        if (this.aliasToListeners[alias].length == 0) {
            this.communicator.invokeRelaxed("registerFieldInterest", contextItemName, fieldName);
        }
        this.aliasToListeners[alias].push(listener);
        return {
            dispose: () => {
                this.aliasToListeners[alias] = ensureArray(this.aliasToListeners[alias]);
                this.aliasToListeners[alias] = this.aliasToListeners[alias].filter((p) => p != listener);
                if (this.aliasToListeners[alias].length == 0) {
                    this.communicator.invokeRelaxed("unregisterFieldInterest", contextItemName, fieldName);
                }
            },
        };
    }
}

export type IRuntimeContextItem = IContextItem &
    (
        | RuntimeDataObjectContextItem<unknown>
        | RuntimeMassDataObjectContextItem<unknown>
        | RuntimeDependentDataObjectsContextItem<unknown>
        | RuntimeUngroupedAggregation
        | RuntimeGroupedAggregation
    );
export type IRuntimeAggregation = IAggregation &
    (RuntimeUngroupedAggregation | RuntimeGroupedAggregation | RuntimeFieldAggregation | RuntimeScriptedAggregation);

export class RuntimeDataObjectContextItem<T> implements IDataObjectContextItem<T> {
    readonly type: "DataObject";
    readonly objectTypeName: string;
    readonly id: string;
    readonly name: string;

    constructor(
        contextItem: IDataObjectContextItemMetadata,
        private contextItemChangeNotifier: ContextItemChangeNotifier,
        private fieldValueChangeNotifier: FieldValueChangeNotifier,
        private communicator: Communicator<Host.IAPI>,
        protected fieldEnhancer: <T extends FieldMetadata>(field: T) => T,
    ) {
        Object.assign(this, contextItem);
    }

    getMetadata(): Promise<Record<StringKeyOf<T>, FieldMetadata>> {
        return this.communicator
            .invokeRelaxed("getMetadata", this.objectTypeName)
            .then((metadata) => enhanceFieldsWithAPIMethods(metadata, this.fieldEnhancer));
    }

    onInvalidate(listener: VoidFunction): IDisposable {
        return this.contextItemChangeNotifier.registerInvalidateInterest(this.name, listener);
    }

    bindField<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(
        fieldName: FIELD,
        listener: FieldChangeListener<T[FIELD]>,
    ): IDisposable {
        this.getField(fieldName).then((field) => listener(field));
        return this.fieldValueChangeNotifier.registerFieldInterest<T, FIELD>(this.name, fieldName, (field) =>
            listener(this.fieldEnhancer(field)),
        );
    }
    getField<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(
        fieldName: FIELD,
    ): Promise<Field<T[FIELD]> & { fieldName: FIELD }> {
        return this.communicator
            .invokeRelaxed("getField", this.name, fieldName)
            .then((field: Field<T[FIELD]> & { fieldName: FIELD }) => this.fieldEnhancer(field));
    }

    getFields<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(...fields: FIELD[]): Promise<FieldsFor<Pick<T, FIELD>>> {
        return this.communicator
            .invokeRelaxed("getFields", this.name, ...fields)
            .then((fields: FieldsFor<Pick<T, FIELD>>) => enhanceFieldsWithAPIMethods(fields, this.fieldEnhancer));
    }

    updateField?<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(
        field: LenientField<T, FIELD> & { fieldName: FIELD },
    ): Promise<void> {
        return this.communicator.invokeRelaxed("updateField", this.name, field);
    }

    updateFields?(fields: Partial<LenientFieldsFor<T>>): Promise<void> {
        return this.communicator.invokeRelaxed("updateFields", this.name, fields);
    }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export class RuntimeDependentDataObjectsContextItem<T = any> implements IDependentDataObjectsContextItem<T> {
    readonly type: "DependentDataObjects";
    readonly objectTypeName: string;
    readonly name: string;
    readonly itemsEditable: boolean;

    constructor(
        contextItem: IDependentDataObjectsContextItemMetadata,
        private contextItemChangeNotifier: ContextItemChangeNotifier,
        private communicator: Communicator<Host.IAPI>,
        protected fieldEnhancer: <T extends FieldMetadata>(field: T) => T,
    ) {
        Object.assign(this, contextItem);
    }

    getMetadata(): Promise<Record<StringKeyOf<T>, FieldMetadata>> {
        return this.communicator
            .invokeRelaxed("getMetadata", this.objectTypeName)
            .then((metadata) => enhanceFieldsWithAPIMethods(metadata, this.fieldEnhancer));
    }

    onInvalidate(listener: VoidFunction): IDisposable {
        return this.contextItemChangeNotifier.registerInvalidateInterest(this.name, listener);
    }

    load<FIELD extends StringKeyOf<T> = StringKeyOf<T>, INCLUDE_SUMMARY extends boolean = false>(
        fieldNames: FIELD[],
        includeSummary?: INCLUDE_SUMMARY,
    ): Promise<ConditionalMassDataResponseType<T, FIELD, INCLUDE_SUMMARY>> {
        return this.communicator
            .invokeRelaxed("dependentDataObjectsOperationLoad", this.name, fieldNames, includeSummary)
            .then((response: ConditionalMassDataResponseType<T, FIELD, typeof includeSummary>) => {
                enhanceMassDataResponseWithAPIMethods(response, this.fieldEnhancer);
                return response;
            });
    }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export class RuntimeMassDataObjectContextItem<T = any> implements IMassDataObjectContextItem<T> {
    readonly type: "MassData";
    readonly objectTypeName: string;
    readonly name: string;
    readonly selection?: ISelection;
    readonly selectionSupported: boolean;

    constructor(
        contextItem: IMassDataObjectContextItemMetadata,
        private contextItemChangeNotifier: ContextItemChangeNotifier,
        private communicator: Communicator<Host.IAPI>,
        protected fieldEnhancer: <T extends FieldMetadata>(field: T) => T,
    ) {
        Object.assign(this, contextItem);
        if (this.selectionSupported) {
            this.selection = new SelectionImpl(contextItem, communicator);
        }
    }

    getMetadata(): Promise<Record<StringKeyOf<T>, FieldMetadata>> {
        return this.communicator
            .invokeRelaxed("getMetadata", this.objectTypeName)
            .then((metadata) => enhanceFieldsWithAPIMethods(metadata, this.fieldEnhancer));
    }

    getViewDefinition(): Promise<IViewDefinition> {
        return this.communicator.invokeRelaxed("getViewDefinition", this.name);
    }

    getSelection(): ISelection {
        return this.selection;
    }

    onInvalidate(listener: VoidFunction): IDisposable {
        return this.contextItemChangeNotifier.registerInvalidateInterest(this.name, listener);
    }

    load<
        FIELD extends StringKeyOf<T> = StringKeyOf<T>,
        INCLUDES_SUMMARY extends boolean = false,
        INCLUDES_SMARTTAGS extends boolean = false,
    >(
        fieldNames: FIELD[],
        from: number,
        pageSize: number,
        where?: string,
        includeSummary?: INCLUDES_SUMMARY,
        includeSmartTags?: INCLUDES_SMARTTAGS,
    ): Promise<ConditionalMassDataResponseType<T, FIELD, INCLUDES_SUMMARY, INCLUDES_SMARTTAGS>> {
        return this.communicator
            .invokeRelaxed(
                "massDataOperationLoad",
                this.name,
                fieldNames,
                from,
                pageSize,
                where,
                includeSummary,
                includeSmartTags,
            )
            .then(
                (
                    response: ConditionalMassDataResponseType<T, FIELD, typeof includeSummary, typeof includeSmartTags>,
                ) => {
                    enhanceMassDataResponseWithAPIMethods(response, this.fieldEnhancer);
                    return response;
                },
            );
    }
    count(): Promise<number> {
        return this.communicator.invokeRelaxed("massDataOperationCount", this.name);
    }
    sum<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(field: FIELD): Promise<number | string | undefined> {
        return this.communicator.invokeRelaxed("massDataOperationSum", this.name, field);
    }
    min<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(field: FIELD): Promise<number | string | undefined> {
        return this.communicator.invokeRelaxed("massDataOperationMin", this.name, field);
    }
    max<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(field: FIELD): Promise<number | string | undefined> {
        return this.communicator.invokeRelaxed("massDataOperationMax", this.name, field);
    }
    average<FIELD extends StringKeyOf<T> = StringKeyOf<T>>(field: FIELD): Promise<number | string | undefined> {
        return this.communicator.invokeRelaxed("massDataOperationAverage", this.name, field);
    }
}

class SelectionImpl implements ISelection {
    private _callbacks: Array<(newSelectionState: SelectionState) => void> = [];

    constructor(
        private contextItem: IMassDataObjectContextItemMetadata,
        private communicator: Communicator<Host.IAPI>,
    ) {
        this.communicator.expose(
            {
                setSelection: (contextItemName: string, selectionState: SelectionState) => {
                    if (this.contextItem.name == contextItemName) {
                        this.setSelection(selectionState);
                    }
                },
            },
            "setSelection",
        );
    }

    onChange(callback: (newSelectionState: SelectionState) => void): IDisposable | undefined {
        if (this._callbacks.length == 0) {
            this.communicator.invokeRelaxed("registerSelectionInterest", this.contextItem.name);
        }
        this._callbacks.push(callback);
        return {
            dispose: () => {
                this._callbacks = this._callbacks.filter((p) => p !== callback);
                if (this._callbacks.length == 0) {
                    this.communicator.invokeRelaxed("unregisterSelectionInterest", this.contextItem.name);
                }
            },
        };
    }

    private setSelection(selectionState: SelectionState) {
        this._callbacks.forEach((callback) => callback(selectionState));
    }

    update(newSelection: SelectionState): Promise<void> {
        return this.set(newSelection.selectAll, newSelection.selectedIds, newSelection.deselectedIds);
    }

    private set(selectAll: boolean, selectedIds: string[], deselectedIds: string[]): Promise<void> {
        return this.communicator.invokeRelaxed(
            "massDataOperationUpdateSelection",
            this.contextItem.name,
            selectAll,
            selectedIds,
            deselectedIds,
        );
    }
}

abstract class RuntimeAggregation implements IAggregationContextItemBase {
    readonly type: "Aggregation";
    readonly name: string;
    grouped: boolean;

    constructor(
        contextItem: IGroupedAggregation | IUngroupedAggregation,
        private contextItemChangeNotifier: ContextItemChangeNotifier,
        protected communicator: Communicator<Host.IAPI>,
    ) {
        Object.assign(this, contextItem);
    }

    onInvalidate(listener: VoidFunction): IDisposable {
        return this.contextItemChangeNotifier.registerInvalidateInterest(this.name, listener);
    }
}

export class RuntimeUngroupedAggregation extends RuntimeAggregation implements IUngroupedAggregation {
    readonly grouped: false;
    get<VALUE>(): Promise<VALUE> {
        return this.communicator.invokeRelaxed("aggregationOperationGet", this.name);
    }
}

export class RuntimeGroupedAggregation extends RuntimeAggregation implements IGroupedAggregation {
    readonly grouped: true;
    get<GROUP, VALUE>(): Promise<GroupResult<GROUP, VALUE>[]> {
        return this.communicator.invokeRelaxed("aggregationOperationGet", this.name);
    }
}

export class RuntimeFieldAggregation extends RuntimeAggregation implements IFieldAggregation {
    readonly grouped: false;
    readonly fieldAggregation: true;

    constructor(
        contextItem: IGroupedAggregation | IUngroupedAggregation,
        contextItemChangeNotifier: ContextItemChangeNotifier,
        communicator: Communicator<Host.IAPI>,
        private fieldEnhancer: <T extends FieldMetadata>(field: T) => T,
    ) {
        super(contextItem, contextItemChangeNotifier, communicator);
    }

    get<VALUE>(): Promise<VALUE> {
        return this.communicator.invokeRelaxed("aggregationOperationGet", this.name);
    }
    getMetadata<T>(): Promise<FieldMetadata<T>> {
        return this.communicator
            .invokeRelaxed("fieldAggregationGetMetadata", this.name)
            .then((field: FieldMetadata<T>) => this.fieldEnhancer(field));
    }
}

export class RuntimeScriptedAggregation implements IScriptedAggregation {
    readonly type: "ScriptedAggregation";
    readonly name: string;
    readonly scriptedAggregation: true;

    constructor(
        contextItem: IScriptedAggregation,
        private contextItemChangeNotifier: ContextItemChangeNotifier,
        protected communicator: Communicator<Host.IAPI>,
    ) {
        Object.assign(this, contextItem);
    }

    onInvalidate(listener: VoidFunction): IDisposable {
        return this.contextItemChangeNotifier.registerInvalidateInterest(this.name, listener);
    }

    get<VALUE extends ScriptedAggregationRawValueTypes>(): Promise<
        ScriptedGroupedAggregationResult<VALUE> | ScriptedUngroupedAggregationResult<VALUE>
    > {
        return this.communicator.invokeRelaxed("scriptedAggregationGet", this.name);
    }
}
